using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client through MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var notebook = new ResearchNotebook();

IList<AITool> tools =
[
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
    AIFunctionFactory.Create(WebSearchTool.FetchPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
];

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic
        the user provides by searching the web, reading relevant pages, and
        taking structured notes.

        Workflow:
        1. Search the web for the topic with several varied queries.
        2. Fetch and read the most relevant pages.
        3. Take notes on each key finding using the add_note tool.
        4. After gathering enough information, call get_notes to review your
           notes, then provide a final, well-organized summary to the user
           with source URLs.

        Always cite sources. Be thorough but concise in the final summary.
        """,
    name: "ResearchAgent",
    tools: tools);

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
