+        CancellationToken cancellationToken = default)
+    {
+        try
+        {
+            var html = await Http.GetStringAsync(url, cancellationToken);
+            var text = StripHtml(html);
+            return text.Length > 4000 ? text[..4000] + "\n...[truncated]" : text;
+        }
+        catch (Exception ex)
+        {
+            return $"Fetch failed: {ex.Message}";
+        }
+    }
+
+    private static string ParseDuckDuckGoResults(string html)
+    {
+        var sb = new StringBuilder();
+        int resultCount = 0;
+
+        // Extract result links and snippets from DuckDuckGo Lite HTML
+        var spans = html.Split("<a rel=\"nofollow\"", StringSplitOptions.None);
+        for (int i = 1; i < spans.Length && resultCount < 8; i++)
+        {
+            var span = spans[i];
+
+            var hrefStart = span.IndexOf("href=\"", StringComparison.Ordinal);
+            if (hrefStart < 0) continue;
+            hrefStart += 6;
+            var hrefEnd = span.IndexOf('"', hrefStart);
+            if (hrefEnd < 0) continue;
+            var href = span[hrefStart..hrefEnd];
+
+            var titleStart = span.IndexOf('>', hrefEnd);
+            if (titleStart < 0) continue;
+            titleStart++;
+            var titleEnd = span.IndexOf("</a>", titleStart, StringComparison.Ordinal);
+            if (titleEnd < 0) continue;
+            var title = StripHtml(span[titleStart..titleEnd]).Trim();
+
+            // Try to grab the snippet (next <td> content)
+            var snippet = "";
+            var tdIdx = span.IndexOf("<td", titleEnd, StringComparison.OrdinalIgnoreCase);
+            if (tdIdx >= 0)
+            {
+                var tdContentStart = span.IndexOf('>', tdIdx) + 1;
+                var tdContentEnd = span.IndexOf("</td>", tdContentStart, StringComparison.OrdinalIgnoreCase);
+                if (tdContentEnd > tdContentStart)
+                    snippet = StripHtml(span[tdContentStart..tdContentEnd]).Trim();
+            }
+
+            if (!string.IsNullOrWhiteSpace(title) && href.StartsWith("http", StringComparison.Ordinal))
+            {
+                resultCount++;
+                sb.AppendLine($"{resultCount}. {title}");
+                sb.AppendLine($"   URL: {href}");
+                if (!string.IsNullOrWhiteSpace(snippet))
+                    sb.AppendLine($"   {snippet}");
+                sb.AppendLine();
+            }
+        }
+
+        return resultCount > 0
+            ? sb.ToString()
+            : "No results found.";
+    }
+
+    private static string StripHtml(string html)
+    {
+        // Remove script/style blocks, then tags, then decode common entities
+        var text = System.Text.RegularExpressions.Regex.Replace(
+            html, @"<(script|style)[^>]*>.*?</\1>", "", 
+            System.Text.RegularExpressions.RegexOptions.Singleline | 
+            System.Text.RegularExpressions.RegexOptions.IgnoreCase);
+        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
+        text = System.Net.WebUtility.HtmlDecode(text);
+        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
+        return text.Trim();
+    }
+}
+
+/// <summary>Structured note-taking tool for the agent.</summary>
+class ResearchNotebook
+{
+    private readonly List<(string Source, string Content)> _notes = [];
+
+    [Description("Save a research note with its source URL. Use this to record key findings.")]
+    public string AddNote(
+        [Description("Source URL for this finding")] string source,
+        [Description("The note content summarizing the finding")] string content)
+    {
+        _notes.Add((source, content));
+        return $"Note #{_notes.Count} saved.";
+    }
+
+    [Description("Retrieve all saved research notes to review before writing the final summary.")]
+    public string GetNotes()
+    {
+        if (_notes.Count == 0) return "No notes saved yet.";
+
+        var sb = new StringBuilder();
+        for (int i = 0; i < _notes.Count; i++)
+        {
+            sb.AppendLine($"[Note {i + 1}] Source: {_notes[i].Source}");
+            sb.AppendLine(_notes[i].Content);
+            sb.AppendLine();
+        }
+        return sb.ToString();
+    }
+}
